def create_schema_fingerprint(schema: Dict[str, Any]) -> str:
    """Create hash-based fingerprint for schema comparison with version metadata."""
    schema_with_meta = {
        'schema': schema,
        'version': datetime.now().isoformat(),
        'fingerprint_algorithm': 'sha256'
    }
