def _compare_schemas(schema1: Dict[str, Any], schema2: Dict[str, Any]) -> Dict[str, Any]:
    """Compare schemas and detect column additions, removals, type changes, and constraint modifications with severity classification."""
    changes = {'breaking_changes': [], 'non_breaking_changes': [], 'severity': 'none'}

    if isinstance(schema1, dict) and isinstance(schema2, dict):
        # For dict schemas (JSON data) with JSONPath tracking
        added_fields = set(schema2.keys()) - set(schema1.keys())
        removed_fields = set(schema1.keys()) - set(schema2.keys())

        # Non-breaking changes
        if added_fields:
            changes['non_breaking_changes'].append({
                'type': 'added_fields',
                'fields': list(added_fields),
                'paths': [f"$.{field}" for field in added_fields]
            })
            changes['severity'] = 'warning'

        # Breaking changes
        if removed_fields:
            changes['breaking_changes'].append({
                'type': 'removed_fields', 
                'fields': list(removed_fields),
                'paths': [f"$.{field}" for field in removed_fields]
            })
            changes['severity'] = 'critical'

        # Type changes with path tracking
        type_changes = {}
        for key in set(schema1.keys()) & set(schema2.keys()):
            if isinstance(schema1[key], dict) and isinstance(schema2[key], dict):
                # Recursive comparison for nested structures with array support
                nested_changes = _compare_schemas(schema1[key], schema2[key])
                if nested_changes['breaking_changes'] or nested_changes['non_breaking_changes']:
                    type_changes[f"$.{key}"] = nested_changes

                # Array schema validation within nested structures
                if 'items' in schema1[key] and 'items' in schema2[key]:
                    array_changes = _compare_schemas(schema1[key]['items'], schema2[key]['items'])
                    if array_changes['breaking_changes'] or array_changes['non_breaking_changes']:
                        type_changes[f"$.{key}.items"] = array_changes

            elif schema1[key] != schema2[key]:
                type_changes[f"$.{key}"] = {
                    'from': schema1[key], 
                    'to': schema2[key],
                    'compatible': _is_type_change_compatible(schema1[key], schema2[key])
                }

        if type_changes:
            # Classify type changes by compatibility
            compatible_changes = {k: v for k, v in type_changes.items() 
                                if v.get('compatible', False)}
            incompatible_changes = {k: v for k, v in type_changes.items() 
                                  if not v.get('compatible', False)}

            if compatible_changes:
                changes['non_breaking_changes'].append({
                    'type': 'compatible_type_changes',
                    'changes': compatible_changes
                })
                changes['severity'] = max(changes['severity'], 'warning', key=lambda x: ['none', 'warning', 'critical'].index(x))

            if incompatible_changes:
                changes['breaking_changes'].append({
                    'type': 'incompatible_type_changes',
                    'changes': incompatible_changes
                })
                changes['severity'] = 'critical'

        # Constraint modifications detection
        constraint_changes = _detect_constraint_changes(schema1, schema2)
        if constraint_changes:
            if constraint_changes.get('breaking'):
                changes['breaking_changes'].append({
                    'type': 'constraint_modifications',
                    'changes': constraint_changes['breaking']
                })
                changes['severity'] = 'critical'
            if constraint_changes.get('non_breaking'):
                changes['non_breaking_changes'].append({
                    'type': 'constraint_enhancements',
                    'changes': constraint_changes['non_breaking']
                })

    return changes

def _is_type_change_compatible(old_type: str, new_type: str) -> bool:
    """Determine if type change is compatible."""
    compatible_mappings = {
        'int': ['bigint', 'float', 'decimal'],
        'varchar': ['text'],
        'date': ['timestamp']
    }
    return new_type in compatible_mappings.get(old_type, [])

def _detect_constraint_changes(schema1: Dict[str, Any], schema2: Dict[str, Any]) -> Dict[str, Any]:
    """Detect constraint modifications like null constraints, length changes."""
    constraint_changes = {'breaking': [], 'non_breaking': []}

    # Check for null constraint changes
    for field in set(schema1.keys()) & set(schema2.keys()):
        if isinstance(schema1.get(field), dict) and isinstance(schema2.get(field), dict):
            old_nullable = schema1[field].get('nullable', True)
            new_nullable = schema2[field].get('nullable', True)

            if old_nullable and not new_nullable:
                constraint_changes['breaking'].append({
                    'field': field,
                    'constraint': 'null',
                    'change': 'nullable_to_not_null'
                })
            elif not old_nullable and new_nullable:
                constraint_changes['non_breaking'].append({
                    'field': field,
                    'constraint': 'null', 
                    'change': 'not_null_to_nullable'
                })

    return constraint_changes

def apply_adaptive_schema_mapping(data: Dict[str, Any], source_type: str, changes: Dict[str, Any]) -> Dict[str, Any]:
    """Apply automatic schema mapping and transformation rules."""
    mapped_data = data.copy()

    if source_type in SCHEMA_MAPPINGS:
        field_mappings = SCHEMA_MAPPINGS[source_type]['field_mappings']

        # Apply field mappings
        for old_field, new_field in field_mappings.items():
            if old_field in mapped_data:
                mapped_data[new_field] = mapped_data.pop(old_field)

        # Apply type transformations for compatible changes
        if changes.get('non_breaking_changes'):
            for change in changes['non_breaking_changes']:
                if change['type'] == 'compatible_type_changes':
                    for path, type_change in change['changes'].items():
                        field_name = path.replace('$.', '')
                        if field_name in mapped_data and 'to' in type_change:
                            mapped_data[field_name] = _transform_field_type(
                                mapped_data[field_name], 
                                type_change['to']
                            )

    return mapped_data

def _transform_field_type(value: Any, target_type: str) -> Any:
    """Transform field value to target type."""
    try:
        if target_type == 'bigint':
            return int(value)
        elif target_type == 'text':
            return str(value)
        elif target_type == 'timestamp':
            return pd.to_datetime(value)
        else:
            return value
    except (ValueError, TypeError):
        return value

def evaluate_partial_processing_capability(data: Dict[str, Any], source_type: str, changes: Dict[str, Any]) -> bool:
    """Evaluate if partial processing can continue with field importance matrix."""
    if source_type not in FIELD_IMPORTANCE_MATRIX:
        return False

    importance_matrix = FIELD_IMPORTANCE_MATRIX[source_type]
    available_fields = set(data.keys())

    # Check critical fields
    critical_fields = set(importance_matrix['critical'])
    missing_critical = critical_fields - available_fields
    critical_missing_ratio = len(missing_critical) / len(critical_fields) if critical_fields else 0

    # Check important fields
    important_fields = set(importance_matrix['important'])
    missing_important = important_fields - available_fields
    important_missing_ratio = len(missing_important) / len(important_fields) if important_fields else 0

    # Check optional fields
    optional_fields = set(importance_matrix['optional'])
    missing_optional = optional_fields - available_fields
    optional_missing_ratio = len(missing_optional) / len(optional_fields) if optional_fields else 0

    # Apply thresholds
    config = PROCESSING_CONFIG['field_importance_thresholds']

    return (critical_missing_ratio <= config['critical_missing_max'] and
            important_missing_ratio <= config['important_missing_max'] and
            optional_missing_ratio <= config['optional_missing_max'])

