def verify_idempotency(current_data: Any, execution_date: str, stage: str) -> bool:
    """Verify idempotency by comparing current run with previous runs with data sampling for large datasets."""
    # For large datasets, use data sampling to improve performance
    if isinstance(current_data, (pd.DataFrame, list)) and len(current_data) > 10000:
        sample_size = min(1000, len(current_data))
        if isinstance(current_data, pd.DataFrame):
            sampled_data = current_data.sample(n=sample_size).reset_index(drop=True)
        else:
            sampled_data = current_data[:sample_size]
        checksum_data = str(sampled_data)
    else:
        checksum_data = str(current_data)

    current_checksum_sha256 = hashlib.sha256(checksum_data.encode()).hexdigest()
    current_checksum_md5 = hashlib.md5(checksum_data.encode()).hexdigest()

    # Compare with previous run
    previous_run_key = f"run_comparison_{stage}_{execution_date}"
    previous_run = Variable.get(previous_run_key, deserialize_json=True, default_var={})

    if previous_run:
        # Check for collision detection
        if (current_checksum_sha256 == previous_run.get('checksum_sha256') and 
            current_checksum_md5 == previous_run.get('checksum_md5')):
            logger.info(f"Idempotency verified for {stage} - identical results")

            # Generate detailed comparison report
            comparison_report = generate_idempotency_report(current_data, previous_run, stage)

            return True
        else:
            logger.warning(f"Idempotency violation detected for {stage}")
            return False

    # Store current run for future comparison
    current_run = {
        'checksum_sha256': current_checksum_sha256,
        'checksum_md5': current_checksum_md5,
        'timestamp': datetime.now().isoformat(),
        'record_count': len(current_data) if hasattr(current_data, '__len__') else 1,
        'data_size': sys.getsizeof(current_data)
    }
    Variable.set(previous_run_key, current_run, serialize_json=True)
    return True

def generate_idempotency_report(current_run: Any, previous_run: Dict[str, Any], stage: str) -> Dict[str, Any]:
