# XCom size validation and intermediate storage patterns
def push_xcom_safe(context: Dict[str, Any], key: str, value: Any, max_size: int = 1024*1024) -> str:
    """Push XCom with size validation and intermediate storage for large data."""
    value_size = sys.getsizeof(value)

    if value_size > max_size:
        # Store large data in S3 and return reference
        s3_key = store_large_data(value, context)
        reference = {
            's3_key': s3_key,
            'size': value_size,
            'type': type(value).__name__,
            'timestamp': datetime.now().isoformat()
        }
        context['task_instance'].xcom_push(key=key, value=reference)
        return s3_key
    else:
        # Small data - store in XCom directly
        context['task_instance'].xcom_push(key=key, value=value)
        return key

def store_large_data(data: Any, context: Dict[str, Any]) -> str:
    """Store large data in S3 and return reference key for intermediate storage."""
    execution_date = context['ds']
    task_id = context['task'].task_id
    dag_id = context['dag'].dag_id

    s3_key = f"temp/{dag_id}/{task_id}/{execution_date}/data.parquet"

