    promises.push(
      axios.get(`${baseURL}/api/users/${Math.floor(Math.random() * 100)}`)
        .catch(err => ({
          error: true,
          status: err.response?.status,
          message: err.message
        }))
    );
  }

  const results = await Promise.all(promises);
  const errors = results.filter(r => r.error);

