### 5.1 Proper Connection Management
```javascript
// routes/users.js - FIXED VERSION
const express = require('express');
const pool = require('../db');
const router = express.Router();

// ✅ Fixed implementation with proper error handling
router.get('/users/:id', async (req, res) => {
  const requestId = req.requestId;
  let client;

  try {
    console.log(`[${requestId}] Acquiring client...`);

    // Set a timeout for connection acquisition
    const clientPromise = pool.connect();
    const timeoutPromise = new Promise((_, reject) => 
      setTimeout(() => reject(new Error('Connection timeout')), 5000)
    );

    client = await Promise.race([clientPromise, timeoutPromise]);
    console.log(`[${requestId}] Client acquired successfully`);

    // Simulate processing time
    await new Promise(resolve => setTimeout(resolve, 100));

    const result = await client.query('SELECT * FROM users WHERE id = $1', [req.params.id]);

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }

    console.log(`[${requestId}] Query successful`);
    res.json(result.rows[0]);

  } catch (error) {
    console.error(`[${requestId}] Error:`, error.message);

    if (error.message === 'Connection timeout') {
      res.status(503).json({ error: 'Service temporarily unavailable' });
    } else {
      res.status(500).json({ error: 'Internal server error' });
    }
  } finally {
    // ✅ Ensure client is always released
    if (client) {
      try {
        console.log(`[${requestId}] Releasing client...`);
        client.release();
        console.log(`[${requestId}] Client released successfully`);
      } catch (releaseError) {
        console.error(`[${requestId}] Error releasing client:`, releaseError.message);
      }
    }
  }
});

module.exports = router;
```

