## Step 7: Error Handling Patterns

### Circuit Breaker and Resilience Patterns

```javascript
// db/resilient-pool.js
class CircuitBreaker {
  constructor(options = {}) {
    this.failureThreshold = options.failureThreshold || 0.5; // 50% failure rate
    this.resetTimeoutMs = options.resetTimeoutMs || 30000;   // 30s timeout
    this.windowSize = options.windowSize || 100;

    this.failures = 0;
    this.requests = 0;
    this.state = 'CLOSED'; // CLOSED, OPEN, HALF_OPEN
    this.nextAttempt = 0;
  }

  async execute(operation) {
    if (this.state === 'OPEN') {
      if (Date.now() < this.nextAttempt) {
        throw new Error('Circuit breaker is OPEN');
      }
      this.state = 'HALF_OPEN';
    }

    try {
      const result = await operation();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  onSuccess() {
    this.failures = 0;
    this.state = 'CLOSED';
  }

  onFailure() {
    this.failures++;
    this.requests++;

    const failureRate = this.failures / this.requests;
    if (failureRate >= this.failureThreshold) {
      this.state = 'OPEN';
      this.nextAttempt = Date.now() + this.resetTimeoutMs;
    }
  }
}

// Enhanced pool with circuit breaker
class ResilientPool {
  constructor(poolConfig) {
    this.pool = new Pool(poolConfig);
    this.circuitBreaker = new CircuitBreaker({
      failureThreshold: 0.5,
      resetTimeoutMs: 30000
    });
  }

  async connect() {
    return await this.circuitBreaker.execute(async () => {
      const client = await this.pool.connect();

      // Wrap with timeout and cancellation
      const originalQuery = client.query.bind(client);
      client.query = async (text, params) => {
        const timeoutId = setTimeout(() => {
          // Cancel the query on timeout
          client.cancel && client.cancel();
        }, 10000);

        try {
          const result = await originalQuery(text, params);
          clearTimeout(timeoutId);
          return result;
        } catch (error) {
          clearTimeout(timeoutId);
          throw error;
        }
      };

      return client;
    });
  }
}
```

