// users/resolvers.ts
const resolvers = {
  User: {
    __resolveReference: async (user: { id: string }, context: any) => {
      return await context.dataSources.userAPI.getUserById(user.id);
    },

    addresses: async (user: any, _: any, context: any) => {
      return await context.dataSources.userAPI.getAddressesByUserId(user.id);
    },

    defaultShippingAddress: async (user: any, _: any, context: any) => {
      return await context.dataSources.userAPI.getDefaultAddress(user.id, 'SHIPPING');
    },

    defaultBillingAddress: async (user: any, _: any, context: any) => {
      return await context.dataSources.userAPI.getDefaultAddress(user.id, 'BILLING');
    },
  },

  Query: {
    me: async (_: any, __: any, context: any) => {
      if (!context.user) throw new Error('Not authenticated');
      return await context.dataSources.userAPI.getUserById(context.user.id);
    },

    user: async (_: any, { id }: { id: string }, context: any) => {
      return await context.dataSources.userAPI.getUserById(id);
    },

    users: async (_: any, { limit, offset }: any, context: any) => {
      return await context.dataSources.userAPI.getUsers(limit, offset);
    },
  },

  Mutation: {
    login: async (_: any, { email, password }: any, context: any) => {
      return await context.dataSources.authAPI.login(email, password);
    },

    register: async (_: any, { input }: any, context: any) => {
      return await context.dataSources.authAPI.register(input);
    },

    updateUser: async (_: any, { input }: any, context: any) => {
      if (!context.user) throw new Error('Not authenticated');
      return await context.dataSources.userAPI.updateUser(context.user.id, input);
    },

    createAddress: async (_: any, { input }: any, context: any) => {
      if (!context.user) throw new Error('Not authenticated');
      return await context.dataSources.userAPI.createAddress(context.user.id, input);
    },
  },
};

export const schema = buildSubgraphSchema({ typeDefs, resolvers });
