## Authorization Implementation

### Field-Level Authorization Directives
```javascript
// authDirective.js
import { mapSchema, getDirective, MapperKind } from '@graphql-tools/utils';
import { defaultFieldResolver } from 'graphql';

function authDirectiveTransformer(schema, directiveName = 'auth') {
  return mapSchema(schema, {
    [MapperKind.FIELD]: (fieldConfig, _fieldName, typeName) => {
      const authDirective = getDirective(schema, fieldConfig, directiveName)?.[0];

      if (authDirective) {
        const { requires } = authDirective;
        const { resolve = defaultFieldResolver } = fieldConfig;

        fieldConfig.resolve = async function(source, args, context, info) {
          // Extract user from context
          const { user, req } = context;

          if (!user) {
            throw new Error('Authentication required');
          }

          // Check role-based authorization
          if (!hasRequiredRole(user, requires)) {
            throw new Error(`Access denied. Required role: ${requires}`);
          }

          // Additional checks for sensitive operations
          if (typeName === 'User' && source?.id !== user.id && !isAdmin(user)) {
            throw new Error('Access denied. Can only access own user data');
          }

          return resolve.call(this, source, args, context, info);
        };
      }

      return fieldConfig;
    }
  });
}

function hasRequiredRole(user, requiredRole) {
  const roleHierarchy = {
    'USER': 0,
    'CUSTOMER_SERVICE': 1,
    'ADMIN': 2
  };

  return roleHierarchy[user.role] >= roleHierarchy[requiredRole];
}

function isAdmin(user) {
  return user.role === 'ADMIN';
}

// Apply to schema
import { buildSubgraphSchema } from '@apollo/subgraph';

const schema = buildSubgraphSchema({ typeDefs, resolvers });
const schemaWithAuth = authDirectiveTransformer(schema);
