### Cross-Service Authorization Context
```javascript
// authContext.js
import jwt from 'jsonwebtoken';

export function createAuthContext(req) {
  const token = extractToken(req);

  if (!token) {
    return { user: null, isAuthenticated: false };
  }

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);

    // Enrich with role information
    const enrichedUser = {
      ...user,
      permissions: getPermissionsForRole(user.role),
      tenantId: user.tenantId // For multi-tenant scenarios
    };

    return { 
      user: enrichedUser, 
      isAuthenticated: true,
      authToken: token // Forward to other services
    };
  } catch (error) {
    console.error('JWT verification failed:', error);
    return { user: null, isAuthenticated: false };
  }
}

function extractToken(req) {
  const authHeader = req.headers.authorization;
  if (authHeader?.startsWith('Bearer ')) {
    return authHeader.substring(7);
  }
  return null;
}

function getPermissionsForRole(role) {
  const rolePermissions = {
    'USER': ['read:own', 'update:own'],
    'CUSTOMER_SERVICE': ['read:own', 'read:orders', 'update:orders'],
    'ADMIN': ['read:all', 'update:all', 'delete:all']
  };

  return rolePermissions[role] || [];
}

// Gateway context propagation
export function propagateAuthHeaders(req) {
  return {
    authorization: req.headers.authorization,
    'x-user-id': req.user?.id,
    'x-user-role': req.user?.role,
    'x-tenant-id': req.user?.tenantId
  };
}
