## Query Complexity Analysis

### Complexity Calculation
```javascript
// complexityAnalysis.js
import { getComplexity, simpleEstimator, fieldExtensionsEstimator } from 'graphql-query-complexity';
import depthLimit from 'graphql-depth-limit';

const complexityLimits = {
  development: 1000,
  staging: 5000,
  production: 10000
};

const federationComplexityMultiplier = {
  // Cross-subgraph queries are more expensive
  'User.orders': 3,
  'Order.payments': 2,
  'Product.variants': 1.5
};

export function createComplexityAnalysis(schema) {
  return {
    requestDidStart() {
      return {
        didResolveOperation({ request, document }) {
          const complexity = getComplexity({
            schema,
            operationName: request.operationName,
            query: document,
            variables: request.variables,
            estimators: [
              fieldExtensionsEstimator(),
              simpleEstimator({ 
                defaultComplexity: 1,
                scalarCost: 1,
                objectCost: 2,
                listFactor: 10,
                introspectionCost: 100
              })
            ],
            // Apply federation overhead
            createComplexityEstimator: (options) => {
              return (args) => {
                const baseComplexity = options.defaultEstimator(args);
                const fieldPath = `${args.type.name}.${args.field.name}`;
                const multiplier = federationComplexityMultiplier[fieldPath] || 1;
                return baseComplexity * multiplier;
              };
            }
          });

          const maxComplexity = complexityLimits[process.env.NODE_ENV] || 1000;

          if (complexity > maxComplexity) {
            throw new Error(
              `Query complexity ${complexity} exceeds maximum allowed ${maxComplexity}`
            );
          }

          // Log high complexity queries for monitoring
          if (complexity > maxComplexity * 0.8) {
            console.warn(`High complexity query: ${complexity}`, {
              operation: request.operationName,
              complexity,
              query: document.loc?.source.body
            });
          }
        }
      };
    }
  };
}

export const depthLimitRule = depthLimit(
  process.env.NODE_ENV === 'production' ? 10 : 15
);
