    createComplexityAnalysis(schema),

    // Error formatting for production
    {
      requestDidStart() {
        return {
          didEncounterErrors(ctx) {
            if (process.env.NODE_ENV === 'production') {
              ctx.errors = ctx.errors.map(error => {
                // Remove stack traces in production
                if (error.extensions?.code === 'INTERNAL_SERVER_ERROR') {
                  return new Error('Internal server error');
                }
                return error;
              });
            }
          }
        };
      }
    },

    // Audit logging
    {
      requestDidStart() {
        return {
          didResolveOperation(ctx) {
            const { request, document } = ctx;

            console.log('GraphQL Operation', {
              operation: request.operationName,
              userId: ctx.contextValue.user?.id,
              complexity: ctx.complexity,
              timestamp: new Date().toISOString(),
              query: document.loc?.source.body
            });
          }
        };
      }
    }
  ],

  // Custom error formatter
  formatError: (error) => {
    if (process.env.NODE_ENV === 'production') {
      // Never expose internal errors in production
      if (!error.extensions?.code || error.extensions.code === 'INTERNAL_SERVER_ERROR') {
        return {
          message: 'Internal server error',
          extensions: { code: 'INTERNAL_SERVER_ERROR' }
        };
      }
    }

    return {
      message: error.message,
      locations: error.locations,
      path: error.path,
      extensions: {
        code: error.extensions?.code,
        timestamp: new Date().toISOString()
      }
    };
  }
});

// Middleware for context creation
