/// TTL precision configuration for balancing accuracy vs performance
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TtlPrecision {
    /// Second-level precision, lowest overhead
    Seconds,
    /// Millisecond-level precision, balanced
    Milliseconds,
    /// Microsecond-level precision, highest accuracy but more overhead
    Microseconds,
}

impl TtlPrecision {
    /// Get the recommended cleanup interval for this precision level
    pub fn cleanup_interval(&self) -> Duration {
        match self {
            TtlPrecision::Seconds => Duration::from_secs(10),
            TtlPrecision::Milliseconds => Duration::from_millis(500),
            TtlPrecision::Microseconds => Duration::from_millis(100),
        }
    }

    /// Check if the given duration exceeds the precision threshold
    pub fn is_expired(&self, expires_at: Instant, now: Instant) -> bool {
        let threshold = match self {
            TtlPrecision::Seconds => Duration::from_millis(500),
            TtlPrecision::Milliseconds => Duration::from_micros(500),
            TtlPrecision::Microseconds => Duration::from_nanos(500),
        };

        now >= expires_at.saturating_sub(threshold)
    }

    /// Get performance impact metrics for this precision level
    pub fn performance_impact(&self) -> (f64, &'static str) {
        match self {
            TtlPrecision::Seconds => (1.0, "Lowest CPU overhead, ~1s accuracy"),
            TtlPrecision::Milliseconds => (2.0, "Balanced overhead vs accuracy"),
            TtlPrecision::Microseconds => (5.0, "Highest accuracy, increased CPU overhead"),
        }
    }
}

