    /// Writers have priority, may block readers
    WriterPreferred,
    /// Adaptive policy based on cache hit rate threshold
    Adaptive { hit_rate_threshold: u8 }, // 0-100%
}

impl RwLockPolicy {
    /// Determine if policy should switch based on current hit rate
    pub fn should_switch(&self, current_hit_rate: f64) -> Option<Self> {
        match self {
            RwLockPolicy::Adaptive { hit_rate_threshold } => {
                let threshold = *hit_rate_threshold as f64 / 100.0;
                if current_hit_rate > threshold {
                    Some(RwLockPolicy::ReaderPreferred)
                } else {
                    Some(RwLockPolicy::WriterPreferred)
                }
            }
            _ => None,
        }
    }
}

