/// Latency metrics for performance monitoring
#[derive(Debug, Clone, Default)]
pub struct LatencyMetrics {
    pub p50: Duration,
    pub p95: Duration,
    pub p99: Duration,
    pub max: Duration,
    pub count: u64,
    pub avg: Duration,
    // Internal tracking for percentile calculation
    samples: Vec<u64>, // Store recent samples for percentile calculation
}

impl LatencyMetrics {
    const MAX_SAMPLES: usize = 10000;

    fn update(&mut self, latency: Duration) {
        self.count += 1;
        let latency_nanos = latency.as_nanos() as u64;

        // Update max
        if latency > self.max {
            self.max = latency;
        }

        // Simple moving average update
        let count = self.count as f64;
        let old_avg_nanos = self.avg.as_nanos() as f64;
        let new_avg_nanos = (old_avg_nanos * (count - 1.0) + latency_nanos as f64) / count;
        self.avg = Duration::from_nanos(new_avg_nanos as u64);

        // Store sample for percentile calculation
        self.samples.push(latency_nanos);
        if self.samples.len() > Self::MAX_SAMPLES {
            self.samples.remove(0);
        }

        // Recalculate percentiles if we have enough samples
        if self.samples.len() >= 20 {
            self.calculate_percentiles();
        }
    }

    fn calculate_percentiles(&mut self) {
        let mut sorted_samples = self.samples.clone();
        sorted_samples.sort_unstable();

        let len = sorted_samples.len();
        if len > 0 {
            self.p50 = Duration::from_nanos(sorted_samples[len * 50 / 100]);
            self.p95 = Duration::from_nanos(sorted_samples[len * 95 / 100]);
            self.p99 = Duration::from_nanos(sorted_samples[len * 99 / 100]);
        }
    }
}

