/// Atomic TTL expiry marker for race-free expiry detection
const EXPIRED_MARKER: u64 = u64::MAX;

/// Internal cache node with TTL and intrusive doubly-linked list pointers
#[repr(align(64))] // Cache line alignment for performance
struct CacheNode<K, V> {
    key: K,
    value: V,
    // Atomic expiry timestamp for race-free TTL handling
    expires_at_nanos: AtomicU64, // 0 = no expiry, EXPIRED_MARKER = expired
    created_at: Instant,
    // Atomic pointers for lock-free LRU list manipulation
    prev: Atomic<CacheNode<K, V>>,
    next: Atomic<CacheNode<K, V>>,
    // Estimated memory usage for this node
    memory_usage: usize,
}

impl<K, V> CacheNode<K, V> {
    fn new(key: K, value: V, ttl: Option<Duration>) -> Self {
        let now = Instant::now();
        let memory_usage = Self::estimate_memory_usage(&key, &value);

        let expires_nanos = if let Some(duration) = ttl {
            (now + duration).duration_since(std::time::UNIX_EPOCH)
                .unwrap_or_default()
                .as_nanos() as u64
        } else {
            0 // No expiry
        };

        Self {
            key,
            value,
            expires_at_nanos: AtomicU64::new(expires_nanos),
            created_at: now,
            prev: Atomic::null(),
            next: Atomic::null(),
            memory_usage,
        }
    }

    fn estimate_memory_usage(key: &K, value: &V) -> usize {
        // Base node size plus estimated key/value sizes
        mem::size_of::<Self>() + 
        mem::size_of::<K>() + 
        mem::size_of::<V>() + 
        64 // Additional overhead estimation
    }

    /// Precise memory usage calculation using size_of_val for dynamic sizing
    fn precise_memory_usage<T>(value: &T) -> usize {
        mem::size_of_val(value) + mem::align_of::<T>()
    }

    /// Atomic TTL expiry check and marking with accuracy tracking
    fn is_expired_atomic(&self, now: Instant) -> (bool, Option<Duration>) {
        let current_nanos = self.expires_at_nanos.load(Ordering::Acquire);

        if current_nanos == 0 {
            return (false, None); // No expiry
        }

        if current_nanos == EXPIRED_MARKER {
            return (true, None); // Already marked expired
        }

        let now_nanos = now.duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_nanos() as u64;

        if now_nanos >= current_nanos {
            let delay = Duration::from_nanos(now_nanos.saturating_sub(current_nanos));
            // Try to atomically mark as expired
            match self.expires_at_nanos.compare_exchange_weak(
                current_nanos,
                EXPIRED_MARKER,
                Ordering::SeqCst, // Global ordering for critical state transitions
                Ordering::Acquire,
            ) {
                Ok(_) => (true, Some(delay)),  // Successfully marked expired
                Err(_) => {
                    // Another thread marked it, check current state
                    (self.expires_at_nanos.load(Ordering::Acquire) == EXPIRED_MARKER, Some(delay))
                }
            }
        } else {
            (false, None)
        }
    }
}

