    fn get_lock_free(&self, key: &K, _key_hash: u64, guard: &Guard) -> Option<&CacheNode<K, V>> {
        // Load atomic snapshot of the hashmap
        let map_ptr = self.atomic_map.load(Ordering::Acquire, guard);

