        let new_owned = Owned::new(new_map);
        let _old_map = self.atomic_map.swap(new_owned.into_shared(guard), Ordering::Release);

        if let Some(old_ptr) = old_ptr {
            // Convert old pointer back to owned for cleanup
            unsafe { Some(Owned::from_raw(old_ptr.as_ptr())) }
        } else {
            None
        }
    }

    fn remove(&self, key: &K, guard: &Guard) -> Option<NonNull<CacheNode<K, V>>> {
        let mut map_guard = self.map.write();
        let result = map_guard.remove(key);

        // Update atomic snapshot after modification
        let new_map = map_guard.clone();
        let new_owned = Owned::new(new_map);
        let _old_map = self.atomic_map.swap(new_owned.into_shared(guard), Ordering::Release);

