    current_policy: parking_lot::RwLock<RwLockPolicy>,

    // Expiry queue memory usage tracking
    expiry_queue_memory: AtomicUsize,
}

impl<K, V, S> CacheInner<K, V, S>
where
    K: Hash + Eq + Clone + Send + Sync + 'static,
    V: Send + Sync + 'static,
    S: BuildHasher + Clone + Send + Sync + 'static,
{
    fn new(config: CacheConfig, hasher: S) -> CacheResult<Arc<Self>> {
        // Validate configuration
        if config.num_shards == 0 || !config.num_shards.is_power_of_two() {
            return Err(CacheError::InvalidConfig {
                reason: "num_shards must be a power of 2 and > 0".to_string(),
            });
        }

        if config.max_entries == 0 {
            return Err(CacheError::InvalidConfig {
                reason: "max_entries must be > 0".to_string(),
            });
        }

        // Create shards with individual hashers
        let shards: Vec<_> = (0..config.num_shards)
            .map(|_| CacheShard::new(hasher.clone()))
            .collect();

        let inner = Arc::new(Self {
            config: config.clone(),
            hasher,
            shards,
            entry_count: AtomicUsize::new(0),
            estimated_memory: AtomicUsize::new(0),
            stats: Arc::new(RwLock::new(CacheStats::default())),
            hit_counter: AtomicU64::new(0),
            miss_counter: AtomicU64::new(0),
            lru_head: Atomic::null(),
            lru_tail: Atomic::null(),
            expiry_queue: Arc::new(RwLock::new(BinaryHeap::new())),
            eviction_thread: parking_lot::Mutex::new(None),
            epoch_manager: epoch::default::Collector::new(),
            ttl_delay_sum: AtomicU64::new(0),
            ttl_delay_count: AtomicUsize::new(0),
            ttl_max_delay: AtomicU64::new(0),
            current_policy: parking_lot::RwLock::new(config.rwlock_policy),
            expiry_queue_memory: AtomicUsize::new(0),
        });

        // Initialize dummy head and tail nodes
        inner.init_lru_list();

        // Start background eviction thread
        inner.start_background_eviction(Arc::downgrade(&inner))?;

        Ok(inner)
    }

    fn init_lru_list(&self) {
        // Create dummy head and tail nodes
        let dummy_key = unsafe { MaybeUninit::<K>::zeroed().assume_init() };
        let dummy_value = unsafe { MaybeUninit::<V>::zeroed().assume_init() };

        let head_node = Owned::new(CacheNode::new(dummy_key, dummy_value, None));
        let dummy_key2 = unsafe { MaybeUninit::<K>::zeroed().assume_init() };
        let dummy_value2 = unsafe { MaybeUninit::<V>::zeroed().assume_init() };
        let tail_node = Owned::new(CacheNode::new(dummy_key2, dummy_value2, None));

        let guard = &self.epoch_manager.register().pin();

        let head_ptr = head_node.into_shared(guard);
        let tail_ptr = tail_node.into_shared(guard);

        // Link head <-> tail with Release ordering for visibility
        unsafe {
            let head_ref = head_ptr.as_ref().unwrap();
            let tail_ref = tail_ptr.as_ref().unwrap();

            head_ref.next.store(tail_ptr, Ordering::Release);
            tail_ref.prev.store(head_ptr, Ordering::Release);
        }

        self.lru_head.store(head_ptr, Ordering::SeqCst);
        self.lru_tail.store(tail_ptr, Ordering::SeqCst);
    }

    /// Runtime lock ordering assertion for development builds
    #[cfg(debug_assertions)]
    fn assert_lock_order(&self, operation: &str) {
        // In debug builds, track lock acquisition order to detect violations
        thread_local! {
            static LOCK_STACK: std::cell::RefCell<Vec<String>> = std::cell::RefCell::new(Vec::new());
        }

        LOCK_STACK.with(|stack| {
            let mut stack = stack.borrow_mut();
            stack.push(operation.to_string());

            // Verify no ordering violations
            let valid_orders = [
                vec!["shard_lock", "lru_update", "stats_update"],
                vec!["shard_lock", "stats_update"],
                vec!["lru_update", "stats_update"],
            ];

            let current_order = stack.join("->");
            let is_valid = valid_orders.iter().any(|order| {
                current_order.contains(&order.join("->"))
            });

            assert!(is_valid, "Lock ordering violation detected: {}", current_order);
        });
    }

    #[cfg(not(debug_assertions))]
    fn assert_lock_order(&self, _operation: &str) {}

    /// Validate LRU list invariants for debugging
    fn validate_lru_invariants(&self) -> bool {
        let guard = self.epoch_manager.register().pin();

        let head = self.lru_head.load(Ordering::Acquire, &guard);
        let tail = self.lru_tail.load(Ordering::Acquire, &guard);

        if let (Some(head_ref), Some(tail_ref)) = 
            (unsafe { head.as_ref() }, unsafe { tail.as_ref() }) {

            // Check head has no prev
            if !head_ref.prev.load(Ordering::Acquire, &guard).is_null() {
                return false;
            }

            // Check tail has no next  
            if !tail_ref.next.load(Ordering::Acquire, &guard).is_null() {
                return false;
            }

            // Walk the list and verify bidirectional links
            let mut current = head;
            let mut count = 0;
            const MAX_ITERATIONS: usize = 1_000_000; // Prevent infinite loops

            while !current.is_null() && count < MAX_ITERATIONS {
                let current_ref = unsafe { current.as_ref().unwrap() };
                let next = current_ref.next.load(Ordering::Acquire, &guard);

                if !next.is_null() {
                    let next_ref = unsafe { next.as_ref().unwrap() };
                    let next_prev = next_ref.prev.load(Ordering::Acquire, &guard);

                    // Verify bidirectional link
                    if next_prev.as_raw() != current.as_raw() {
                        return false;
                    }
                }

                current = next;
                count += 1;
            }

            count < MAX_ITERATIONS
        } else {
            false
        }
    }

    fn hash_key(&self, key: &K) -> u64 {
        let mut hasher = self.hasher.build_hasher();
        key.hash(&mut hasher);
        hasher.finish()
    }

    fn get_shard(&self, key: &K) -> &CacheShard<K, V, S> {
        let hash = self.hash_key(key);
        let shard_idx = (hash as usize) & (self.shards.len() - 1);
        &self.shards[shard_idx]
    }

    /// Lock-free read operation using epoch-based protection with latency tracking
    fn get(&self, key: &K) -> Option<CacheRef<V>> {
        let start_time = Instant::now();
        let guard = self.epoch_manager.register().pin();
        let now = Instant::now();
        let key_hash = self.hash_key(key);

        let shard = self.get_shard(key);

        if let Some(node) = shard.get_lock_free(key, key_hash, &guard) {
            // Atomic TTL expiry check with accuracy tracking
            let (is_expired, delay) = node.is_expired_atomic(now);

            // Track TTL accuracy metrics
            if let Some(delay) = delay {
                self.update_ttl_accuracy(delay);
            }

            if is_expired {
                // Immediate memory reclamation on expiry
                self.remove_and_reclaim_immediate(key, node);

                self.miss_counter.fetch_add(1, Ordering::Relaxed);
                self.update_stats(|stats| {
                    stats.misses += 1;
                    stats.evictions_ttl += 1;
                });

                return None;
            }

            // Promote node in LRU order (lock-free when possible)
            self.promote_to_head_atomic(node, &guard);

            // Update hit statistics with atomic counters
            self.hit_counter.fetch_add(1, Ordering::Relaxed);

            let latency = start_time.elapsed();
            self.update_stats(|stats| {
                stats.hits += 1;
                stats.latency.update(latency);
            });

            Some(CacheRef::new(&node.value, guard))
        } else {
            self.miss_counter.fetch_add(1, Ordering::Relaxed);
            let latency = start_time.elapsed();
            self.update_stats(|stats| {
                stats.misses += 1;
                stats.latency.update(latency);
            });
            None
        }
    }

    /// Atomic promotion to head of LRU list maintaining lock-free coherence
    fn promote_to_head_atomic(&self, node: &CacheNode<K, V>, guard: &Guard) {
        let head = self.lru_head.load(Ordering::Acquire, guard);

        if let Some(head_ref) = unsafe { head.as_ref() } {
            let node_shared = Shared::from(node as *const _ as *mut _);

            // Check if already at head (optimization)
            let head_next = head_ref.next.load(Ordering::Acquire, guard);
            if head_next.as_raw() == node_shared.as_raw() {
                return; // Already at head
            }

            // Atomic removal from current position in LRU list
            self.unlink_from_lru_atomic(node, guard);

            // Atomic insertion at head of LRU list
            self.insert_at_head_atomic(node, head_ref, guard);
        }
    }

    /// Atomically unlink node from its current LRU position
    fn unlink_from_lru_atomic(&self, node: &CacheNode<K, V>, guard: &Guard) {
        let prev = node.prev.load(Ordering::Acquire, guard);
        let next = node.next.load(Ordering::Acquire, guard);

        if let (Some(prev_ref), Some(next_ref)) = 
            (unsafe { prev.as_ref() }, unsafe { next.as_ref() }) {

            // Update pointers with Release ordering for immediate visibility
            prev_ref.next.store(next, Ordering::Release);
            next_ref.prev.store(prev, Ordering::Release);
        }
    }

    /// Atomically insert node at head of LRU list
    fn insert_at_head_atomic(&self, node: &CacheNode<K, V>, head_ref: &CacheNode<K, V>, guard: &Guard) {
        let node_shared = Shared::from(node as *const _ as *mut _);
        let head_shared = Shared::from(head_ref as *const _ as *mut _);

        // Get current first node
        let old_first = head_ref.next.load(Ordering::Acquire, guard);

        // Update node pointers
        node.prev.store(head_shared, Ordering::Release);
        node.next.store(old_first, Ordering::Release);

        // Update surrounding nodes with Release ordering for coherence
        if let Some(old_first_ref) = unsafe { old_first.as_ref() } {
            old_first_ref.prev.store(node_shared, Ordering::Release);
        }
        head_ref.next.store(node_shared, Ordering::Release);
    }

    /// Remove LRU tail node for eviction
    fn remove_lru_tail(&self, guard: &Guard) -> Option<K> {
        let tail = self.lru_tail.load(Ordering::Acquire, guard);

        if let Some(tail_ref) = unsafe { tail.as_ref() } {
            let prev = tail_ref.prev.load(Ordering::Acquire, guard);

            if let Some(prev_ref) = unsafe { prev.as_ref() } {
                // Check if this is a real node (not dummy head)
                let head = self.lru_head.load(Ordering::Acquire, guard);
                if prev.as_raw() != head.as_raw() {
                    // Remove from LRU list
                    self.unlink_from_lru_atomic(prev_ref, guard);
                    return Some(prev_ref.key.clone());
                }
            }
        }
        None
    }

    /// Remove and reclaim memory immediately for expired entries
    fn remove_and_reclaim_immediate(&self, key: &K, node: &CacheNode<K, V>) {
        let guard = self.epoch_manager.register().pin();
        let shard = self.get_shard(key);

        if shard.remove(key, &guard).is_some() {
            // Remove from LRU list
            self.unlink_from_lru_atomic(node, &guard);

            // Update counters immediately with AcqRel ordering for coordination
            self.entry_count.fetch_sub(1, Ordering::AcqRel);
            self.estimated_memory.fetch_sub(node.memory_usage, Ordering::AcqRel);

            // Schedule for deferred cleanup
            let owned_node = unsafe { Owned::from_raw(node as *const _ as *mut _) };
            unsafe { guard.defer_destroy(owned_node); }
        }
    }

    /// Insert or update a cache entry with proper eviction and bounds checking
    fn insert(&self, key: K, value: V, ttl: Option<Duration>) -> CacheResult<()> {
        let guard = self.epoch_manager.register().pin();
        let now = Instant::now();

        // Check entry count bounds with compare_exchange for strict enforcement
        let current_count = self.entry_count.load(Ordering::Acquire);
        if current_count >= self.config.max_entries {
            return Err(CacheError::CapacityExceeded {
                max: self.config.max_entries,
                current: current_count,
            });
        }

        // Create new node with precise memory calculation
        let new_node = CacheNode::new(key.clone(), value, ttl.or(self.config.default_ttl));
        let memory_needed = CacheNode::precise_memory_usage(&new_node);

