        let current_memory = self.estimated_memory.load(Ordering::Acquire);
        let total_memory_needed = current_memory + memory_needed + self.ttl_overhead_bytes();

        if total_memory_needed > self.config.max_memory_bytes {
            return Err(CacheError::MemoryExceeded {
                max: self.config.max_memory_bytes,
                current: total_memory_needed,
            });
        }

        let shard = self.get_shard(&key);
        let owned_node = Owned::new(new_node);
        let node_ref = unsafe { owned_node.as_ref() };

