    }

    /// Add entry to TTL expiry queue with prioritized processing
    fn add_to_expiry_queue(&self, entry: ExpiryEntry<K>) {
        if let Ok(mut queue) = self.expiry_queue.try_write() {
            let entry_memory = mem::size_of::<ExpiryEntry<K>>();
            queue.push(entry);
            self.expiry_queue_memory.fetch_add(entry_memory, Ordering::Relaxed);
        }
    }

    /// Remove an entry from the cache
    fn remove(&self, key: &K) -> bool {
        let guard = self.epoch_manager.register().pin();
        let shard = self.get_shard(key);

        self.assert_lock_order("shard_lock");

        if let Some(node_ptr) = shard.remove(key, &guard) {
