  default     = ""

  validation {
    condition = var.domain_name == "" || can(regex("^([a-z0-9]+(-[a-z0-9]+)*\\.)+[a-z]{2,}$", var.domain_name))
    error_message = "Domain name must be a valid FQDN format or empty string."
