# Environment configuration validation with cross-variable dependencies
locals {
  workspace_valid = contains(var.allowed_workspaces, terraform.workspace)

  # Cross-variable validation: ensure prod workspace has required settings
  prod_validation = terraform.workspace != "prod" || (
    var.notification_email != "" &&
    length(var.kms_key_admin_arns) > 0
  )
}

# Check for valid workspace
check "valid_workspace" {
  assert {
    condition     = local.workspace_valid
    error_message = "Workspace '${terraform.workspace}' is not in allowed list: ${join(", ", var.allowed_workspaces)}"
  }
}

check "production_requirements" {
  assert {
    condition = local.prod_validation
    error_message = "Production workspace requires notification_email and kms_key_admin_arns to be specified."
  }
}

