  backup_retention_period = local.env_config[local.environment].backup_retention_period
  backup_window          = local.env_config[local.environment].backup_window

  # Network configuration
  vpc_id                = module.networking.vpc_id
  database_subnet_ids   = module.networking.database_subnet_ids
  database_security_group_id = module.security.database_security_group_id

  # Encryption
  kms_key_id = module.kms.rds_key_id

  tags = local.common_tags
}

# Load Balancer Module
module "load_balancer" {
  source = "./modules/load_balancer"

  environment     = local.environment
  project_name    = var.project_name
  vpc_id          = module.networking.vpc_id
  public_subnet_ids = module.networking.public_subnet_ids
  alb_security_group_id = module.security.alb_security_group_id

  # SSL Configuration
  domain_name = var.domain_name

  tags = local.common_tags
}

# Compute Module (ECS)
module "compute" {
  source = "./modules/compute"

  # Environment configuration
  environment     = local.environment
  project_name    = var.project_name

  # ECS configuration
  task_count            = local.env_config[local.environment].ecs_task_count
  container_image       = var.container_image
  enable_auto_scaling   = local.env_config[local.environment].enable_auto_scaling

